def topo_sort(graph):
    """graph: dict node -> list of nodes it points to. Return an ordering where
    every node precedes the nodes it points to. Raise ValueError on a cycle."""
    visited = set()
    result = []

    def visit(n):
        if n in visited:
            return
        visited.add(n)
        for m in graph.get(n, []):
            visit(m)
        result.append(n)

    for n in list(graph):
        visit(n)
    return result[::-1]

