from graph import topo_sort

def nodes_of(g):
    ns = set(g)
    for u in g:
        ns.update(g[u])
    return ns

def check_order(g):
    order = topo_sort(g)
    assert sorted(order) == sorted(nodes_of(g)), (order, sorted(nodes_of(g)))
    pos = {n: i for i, n in enumerate(order)}
    for u in g:
        for v in g[u]:
            assert pos[u] < pos[v], "%r must precede %r" % (u, v)

